200	function executionFailureError(input: {
201	  provider: ProviderName;
202	  stderr: string;
203	  errorCode?: string;
204	}): CliError {
205	  if (input.errorCode === "ENOENT") {
206	    return blockedError(
207	      "PROVIDER_UNAVAILABLE",
208	      `Provider executable is unavailable for ${input.provider}.`,
209	      input.stderr
210	    );
211	  }
