220	async function executeVerifier(input: {
221	  provider: ProviderName;
222	  specPackRoot: string;
223	  model: string;
224	  reasoningEffort: string;
225	  prompt: string;
226	  env?: Record<string, string | undefined>;
227	}): Promise<VerifierExecutionSuccess | VerifierExecutionFailure> {
228	  const adapter = createProviderAdapter(input.provider, {
229	    env: input.env,
230	  });
231	  const execution = await adapter.execute({
232	    prompt: input.prompt,
233	    cwd: input.specPackRoot,
234	    model: input.model,
235	    reasoningEffort: input.reasoningEffort,
236	    timeoutMs: 30_000,
237	    resultSchema: providerPayloadSchema,
238	  });
239	
240	  if (execution.exitCode !== 0) {
241	    return {
242	      errors: [
243	        executionFailureError({
244	          provider: input.provider,
245	          stderr: execution.stderr,
246	          errorCode: execution.errorCode,
247	        }),
248	      ],
249	    };
250	  }
251	
252	  if (execution.parseError || !execution.parsedResult) {
253	    return {
254	      errors: [
255	        blockedError(
256	          "PROVIDER_OUTPUT_INVALID",
257	          `Provider output was invalid for ${input.provider}.`,
258	          execution.parseError
259	        ),
260	      ],
261	    };
262	  }
263	
264	  return {
265	    payload: execution.parsedResult,
266	  };
267	}
