501	}) {
502	  return {
503	    command: input.command,
504	    version: 1 as const,
505	    status: statusForOutcome(input.outcome),
506	    outcome: input.outcome,
507	    result: input.result,
508	    errors: input.errors ?? [],
509	    warnings: input.warnings ?? [],
510	    artifacts: input.artifacts ?? [],
511	    startedAt: input.startedAt,
512	    finishedAt: input.finishedAt,
513	  };
