 13	  type EpicCleanupResult,
 14	} from "./result-contracts";
 15	import { inspectSpecPack } from "./spec-pack";
 16	
 17	const providerPayloadSchema = epicCleanupResultSchema.omit({
 18	  resultId: true,
 19	}).strict();
 20	
 21	type ProviderPayload = z.infer<typeof providerPayloadSchema>;
 22	
 23	export interface EpicCleanupWorkflowResult {
 24	  outcome: "cleaned" | "needs-more-cleanup" | "blocked";
 25	  result?: EpicCleanupResult;
 26	  errors: CliError[];
 27	  warnings: string[];
 28	}
 29	
 30	interface PreparedCleanupContext {
 31	  specPackRoot: string;
 32	  cleanupBatchPath: string;
 33	  cleanupBatchContent: string;
 34	  provider: ProviderName;
 35	  model: string;
 36	  reasoningEffort: string;
 37	  gateCommands: {
 38	    story: string;
 39	    epic: string;
 40	  };
 41	}
 42	
 43	function blockedError(code: string, message: string, detail?: string): CliError {
 44	  return {
 45	    code,
 46	    message,
 47	    ...(detail ? { detail } : {}),
 48	  };
 49	}
 50	
 51	function providerForHarness(harness: "codex" | "copilot" | "none"): ProviderName {
 52	  if (harness === "none") {
 53	    return "claude-code";
 54	  }
 55	
 56	  return harness;
 57	}
 58	
 59	function executionFailureError(input: {
 60	  provider: ProviderName;
 61	  stderr: string;
 62	  errorCode?: string;
 63	}): CliError {
 64	  if (input.errorCode === "ENOENT") {
 65	    return blockedError(
 66	      "PROVIDER_UNAVAILABLE",
 67	      `Provider executable is unavailable for ${input.provider}.`,
 68	      input.stderr
 69	    );
 70	  }
 71	
 72	  return blockedError(
 73	    "PROVIDER_UNAVAILABLE",
 74	    `Provider execution failed for ${input.provider}.`,
 75	    input.stderr
 76	  );
 77	}
 78	
 79	async function prepareCleanupContext(input: {
 80	  specPackRoot: string;
 81	  cleanupBatchPath: string;
 82	  configPath?: string;
 83	}): Promise<PreparedCleanupContext | { errors: CliError[] }> {
 84	  const inspection = await inspectSpecPack(input.specPackRoot);
 85	  if (inspection.status !== "ready") {
 86	    return {
 87	      errors: [
 88	        blockedError(
 89	          "INVALID_SPEC_PACK",
 90	          "Spec-pack inspection must be ready before epic cleanup can start.",
 91	          inspection.blockers.join("; ") || inspection.notes.join("; ")
 92	        ),
 93	      ],
 94	    };
 95	  }
 96	
 97	  const cleanupBatchPath = resolve(input.cleanupBatchPath);
 98	  if (!(await pathExists(cleanupBatchPath))) {
 99	    return {
100	      errors: [
101	        blockedError(
102	          "INVALID_SPEC_PACK",
103	          `Cleanup batch artifact was not found: ${cleanupBatchPath}`
104	        ),
105	      ],
106	    };
107	  }
108	
109	  const config = await loadRunConfig({
110	    specPackRoot: inspection.specPackRoot,
111	    configPath: input.configPath,
112	  });
113	  const gateResolution = await resolveVerificationGates({
114	    specPackRoot: inspection.specPackRoot,
115	  });
116	  if (gateResolution.status !== "ready" || !gateResolution.verificationGates) {
117	    return {
118	      errors: gateResolution.errors.length
119	        ? gateResolution.errors
120	        : [
121	            blockedError(
122	              "VERIFICATION_GATE_UNRESOLVED",
123	              "Verification gates must be resolved before epic cleanup can start."
124	            ),
125	          ],
126	    };
127	  }
128	
129	  return {
130	    specPackRoot: inspection.specPackRoot,
131	    cleanupBatchPath,
132	    cleanupBatchContent: await readTextFile(cleanupBatchPath),
133	    provider: providerForHarness(config.quick_fixer.secondary_harness),
134	    model: config.quick_fixer.model,
135	    reasoningEffort: config.quick_fixer.reasoning_effort,
136	    gateCommands: {
137	      story: gateResolution.verificationGates.storyGate,
138	      epic: gateResolution.verificationGates.epicGate,
139	    },
140	  };
141	}
142	
143	function hasApprovedCleanupItems(content: string): boolean {
144	  return /\bAPPROVED\b/i.test(content);
145	}
146	
147	function buildCleanupPrompt(context: PreparedCleanupContext): string {
148	  return [
149	    "# Epic Cleanup",
150	    "",
151	    "Apply only the approved cleanup items from the curated cleanup batch.",
152	    "Do not choose a different workflow, widen the scope, or decide whether the epic can close.",
153	    "Use the cleanup batch as the source of truth for this pass.",
154	    "",
155	    `Cleanup batch path: ${context.cleanupBatchPath}`,
156	    `Story gate command: ${context.gateCommands.story}`,
157	    `Epic gate command: ${context.gateCommands.epic}`,
158	    "",
159	    "## Cleanup Batch",
160	    context.cleanupBatchContent.trim(),
161	    "",
162	    "## Output Contract",
163	    "Return exactly one JSON object with: outcome, cleanupBatchPath, filesChanged, changeSummary, gatesRun, unresolvedConcerns, recommendedNextStep.",
164	  ].join("\n");
165	}
166	
167	function buildCleanupResult(input: {
168	  cleanupBatchPath: string;
169	  payload: ProviderPayload;
170	}): EpicCleanupResult {
171	  return {
172	    resultId: randomUUID(),
173	    outcome: input.payload.outcome,
174	    cleanupBatchPath: input.cleanupBatchPath,
175	    filesChanged: input.payload.filesChanged,
176	    changeSummary: input.payload.changeSummary,
177	    gatesRun: input.payload.gatesRun,
178	    unresolvedConcerns: input.payload.unresolvedConcerns,
179	    recommendedNextStep: input.payload.recommendedNextStep,
180	  };
181	}
182	
183	export async function runEpicCleanup(input: {
184	  specPackRoot: string;
185	  cleanupBatchPath: string;
186	  configPath?: string;
187	  env?: Record<string, string | undefined>;
188	}): Promise<EpicCleanupWorkflowResult> {
189	  const context = await prepareCleanupContext(input);
190	  if ("errors" in context) {
191	    return {
192	      outcome: "blocked",
193	      errors: context.errors,
194	      warnings: [],
195	    };
196	  }
197	
198	  if (!hasApprovedCleanupItems(context.cleanupBatchContent)) {
199	    return {
200	      outcome: "cleaned",
201	      result: {
202	        resultId: randomUUID(),
203	        outcome: "cleaned",
204	        cleanupBatchPath: context.cleanupBatchPath,
205	        filesChanged: [],
206	        changeSummary:
207	          "No approved cleanup corrections remained, so the cleanup pass was a no-op.",
208	        gatesRun: [],
209	        unresolvedConcerns: [],
210	        recommendedNextStep:
211	          "Review the cleanup result, then launch epic verification.",
212	      },
213	      errors: [],
214	      warnings: [],
215	    };
216	  }
217	
218	  const adapter = createProviderAdapter(context.provider, {
219	    env: input.env,
220	  });
221	  const execution = await adapter.execute({
222	    prompt: buildCleanupPrompt(context),
223	    cwd: context.specPackRoot,
224	    model: context.model,
225	    reasoningEffort: context.reasoningEffort,
226	    timeoutMs: 30_000,
227	    resultSchema: providerPayloadSchema,
228	  });
229	
230	  if (execution.exitCode !== 0) {
231	    return {
232	      outcome: "blocked",
233	      errors: [
234	        executionFailureError({
235	          provider: context.provider,
236	          stderr: execution.stderr,
237	          errorCode: execution.errorCode,
238	        }),
239	      ],
240	      warnings: [],
241	    };
242	  }
243	
244	  if (execution.parseError || !execution.parsedResult) {
245	    return {
246	      outcome: "blocked",
247	      errors: [
248	        blockedError(
249	          "PROVIDER_OUTPUT_INVALID",
250	          `Provider output was invalid for ${context.provider}.`,
251	          execution.parseError
252	        ),
253	      ],
254	      warnings: [],
255	    };
256	  }
257	
258	  const result = buildCleanupResult({
259	    cleanupBatchPath: context.cleanupBatchPath,
260	    payload: execution.parsedResult,
261	  });
262	
263	  return {
264	    outcome: result.outcome,
265	    result,
266	    errors: [],
267	    warnings: [],
268	  };
269	}

