 18	  version: 1;
 19	  status: CliStatus;
 20	  outcome: string;
 21	  result?: unknown;
 22	  errors: CliError[];
 23	  warnings: string[];
 24	  artifacts: CliArtifactRef[];
 25	  startedAt: string;
