 27	}
 28	
 29	function renderHumanSummary(envelope: OutputEnvelope) {
 30	  if (
 31	    typeof envelope.result !== "object" ||
 32	    envelope.result === null ||
 33	    !("story" in envelope.result)
 34	  ) {
 35	    return `story-implement: ${envelope.outcome}`;
 36	  }
 37	
 38	  const result = envelope.result as {
 39	    story: {
 40	      id: string;
 41	    };
 42	    sessionId: string;
 43	  };
 44	  return [
 45	    `story-implement: ${envelope.outcome}`,
 46	    `story: ${result.story.id}`,
 47	    `session: ${result.sessionId}`,
 48	  ].join("\n");
 49	}
 50	
 51	function emitOutput(params: {
 52	  envelope: OutputEnvelope;
 53	  json: boolean;
 54	}) {
 55	  if (params.json) {
 56	    console.log(JSON.stringify(params.envelope));
 57	    return;
 58	  }
 59	
 60	  console.log(renderHumanSummary(params.envelope));
 61	}
