 63	export default defineCommand({
 64	  meta: {
 65	    name: "story-implement",
 66	    description: "Launch the retained story implementor and run the self-review loop.",
 67	  },
 68	  args: {
 69	    "spec-pack-root": {
 70	      type: "string",
 71	      description: "Absolute or relative path to the spec-pack root",
 72	      required: true,
 73	    },
 74	    "story-id": {
 75	      type: "string",
 76	      description: "The story id to implement",
 77	      required: true,
 78	    },
 79	    config: {
 80	      type: "string",
 81	      description: "Explicit run-config file relative to the spec-pack root",
 82	    },
 83	    json: {
 84	      type: "boolean",
 85	      description: "Emit the structured JSON envelope on stdout",
 86	    },
 87	  },
 88	  async run({ args }) {
 89	    const startedAt = new Date().toISOString();
 90	    const artifactPath = await nextGroupedArtifactPath(
 91	      args["spec-pack-root"],
 92	      args["story-id"],
 93	      "implementor"
 94	    );
 95	
 96	    try {
 97	      const outcome = await runStoryImplement({
 98	        specPackRoot: args["spec-pack-root"],
 99	        storyId: args["story-id"],
100	        configPath: args.config,
101	        env: process.env,
102	      });
103	      const envelope = cliResultEnvelopeSchema(implementorResultSchema).parse(
104	        createResultEnvelope({
105	          command: "story-implement",
106	          outcome: outcome.outcome,
107	          result: outcome.result,
108	          errors: outcome.errors,
109	          warnings: outcome.warnings,
110	          artifacts: [
111	            {
112	              kind: "result-envelope",
113	              path: artifactPath,
114	            },
115	          ],
116	          startedAt,
117	          finishedAt: new Date().toISOString(),
118	        })
119	      );
120	
121	      await writeJsonArtifact(artifactPath, envelope);
122	      emitOutput({
123	        envelope,
124	        json: Boolean(args.json),
125	      });
126	      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
127	    } catch (error) {
128	      const envelope: OutputEnvelope = createResultEnvelope({
129	        command: "story-implement",
130	        outcome:
131	          error instanceof ZodError ||
132	          (error instanceof Error &&
133	            error.message.toLowerCase().includes("config"))
134	            ? "blocked"
135	            : "error",
136	        errors: [
137	          {
138	            code:
139	              error instanceof ZodError ||
140	              (error instanceof Error &&
141	                error.message.toLowerCase().includes("config"))
142	                ? "INVALID_RUN_CONFIG"
143	                : "UNEXPECTED_ERROR",
144	            message: error instanceof Error ? error.message : String(error),
145	          },
146	        ],
147	        artifacts: [
148	          {
149	            kind: "result-envelope",
150	            path: artifactPath,
151	          },
152	        ],
153	        startedAt,
154	        finishedAt: new Date().toISOString(),
155	      });
156	
157	      await writeJsonArtifact(artifactPath, envelope);
158	      emitOutput({
159	        envelope,
160	        json: Boolean(args.json),
161	      });
162	      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
163	    }
